from itertools import combinations

class Solution:
    def minPartitionScore(self, nums, k):
        n = len(nums)
        if k == 1:
            s = sum(nums)
            return s * (s + 1) // 2
        best = None
        gaps = list(range(1, n))
        for cuts in combinations(gaps, k - 1):
            bounds = [0] + list(cuts) + [n]
            score = 0
            for a, b in zip(bounds, bounds[1:]):
                s = sum(nums[a:b])
                score += s * (s + 1) // 2
            if best is None or score < best:
                best = score
        return best

