class Solution:
    def minPartitionScore(self, nums, k):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i, x in enumerate(nums):
            prefix[i + 1] = prefix[i] + x

        def tri(s):
            return s * (s + 1) // 2

        INF = float('inf')
        dp_prev = [INF] * (n + 1)
        dp_prev[0] = 0
        for j in range(1, k + 1):
            dp_cur = [INF] * (n + 1)
            for i in range(j, n + 1):
                best = INF
                for m in range(j - 1, i):
                    if dp_prev[m] == INF:
                        continue
                    s = prefix[i] - prefix[m]
                    cand = dp_prev[m] + tri(s)
                    if cand < best:
                        best = cand
                dp_cur[i] = best
            dp_prev = dp_cur
        return dp_prev[n]

