var minPartitionScore = function(nums, k) {
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];

    const tri = (s) => (s * (s + 1)) / 2;

    const INF = Infinity;
    let dpPrev = new Array(n + 1).fill(INF);
    dpPrev[0] = 0;
    for (let j = 1; j <= k; j++) {
        const dpCur = new Array(n + 1).fill(INF);
        for (let i = j; i <= n; i++) {
            let best = INF;
            for (let m = j - 1; m < i; m++) {
                if (dpPrev[m] === INF) continue;
                const s = prefix[i] - prefix[m];
                const cand = dpPrev[m] + tri(s);
                if (cand < best) best = cand;
            }
            dpCur[i] = best;
        }
        dpPrev = dpCur;
    }
    return dpPrev[n];
};
